import{_ as n,o as t,c as i,ag as a}from"./chunks/framework.NIzFHKo_.js";const m=JSON.parse('{"title":"QiEvidence Domain (QiEn)","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/30_data/150_qievidence.md","filePath":"10_core/30_data/150_qievidence.md"}'),s={name:"10_core/30_data/150_qievidence.md"};function o(r,e,d,c,l,p){return t(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="qievidence-domain-qien" tabindex="-1">QiEvidence Domain (QiEn) <a class="header-anchor" href="#qievidence-domain-qien" aria-label="Permalink to &quot;QiEvidence Domain (QiEn)&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>QiEvidence (internal engine name: <strong>QiEn</strong>) is a local-first evidence intelligence module that transforms raw multimedia and documents (videos, photos, PDFs, audio, screenshots, etc.) into a structured, cross-referenced, searchable evidence archive.</p><p>Core capabilities:</p><ul><li>Timestamped transcription and visual event extraction</li><li>Neutral, cold, objective narration (no emotion, no speculation, no mind-reading)</li><li>Entity normalization and tracking (people, vehicles, locations, accounts, etc.)</li><li>Automated contradiction / inconsistency detection</li><li>Master timeline assembly across all artifacts</li><li>Human review queue for uncertain or conflicting items</li></ul><p>It is a disciplined evidence-processing engine with two brains:</p><ul><li><strong>Extractor</strong>: Factual, structured output only.</li><li><strong>Analyst</strong>: Cross-referencing, flagging, and neutral narration.</li></ul><h2 id="folder-structure" tabindex="-1">Folder Structure <a class="header-anchor" href="#folder-structure" aria-label="Permalink to &quot;Folder Structure&quot;">​</a></h2><p>The local execution environment uses a standardized folder hierarchy:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/QiEvidence/</span></span>
<span class="line"><span>├── input/</span></span>
<span class="line"><span>│   ├── videos/</span></span>
<span class="line"><span>│   ├── photos/</span></span>
<span class="line"><span>│   ├── documents/</span></span>
<span class="line"><span>│   └── other/</span></span>
<span class="line"><span>├── working/</span></span>
<span class="line"><span>│   ├── audio/</span></span>
<span class="line"><span>│   ├── frames/</span></span>
<span class="line"><span>│   └── transcripts/</span></span>
<span class="line"><span>├── output/</span></span>
<span class="line"><span>│   ├── events/</span></span>
<span class="line"><span>│   ├── entities/</span></span>
<span class="line"><span>│   ├── timelines/</span></span>
<span class="line"><span>│   ├── reports/</span></span>
<span class="line"><span>│   └── reviews/</span></span>
<span class="line"><span>└── archive/ (hashed originals + metadata)</span></span></code></pre></div><h2 id="schema-qievidence" tabindex="-1">Schema: <code>qievidence</code> <a class="header-anchor" href="#schema-qievidence" aria-label="Permalink to &quot;Schema: \`qievidence\`&quot;">​</a></h2><p>The domain uses the following tables, linked to <code>qione.tenants</code> and <code>qicase.cases</code>.</p><table tabindex="0"><thead><tr><th>Table</th><th>Description</th></tr></thead><tbody><tr><td><code>evidence_records</code></td><td>Master artifact registry (one row per file)</td></tr><tr><td><code>evidence_segments</code></td><td>Chunked slices of long media/documents</td></tr><tr><td><code>evidence_entities</code></td><td>Canonical people, vehicles, locations, accounts, etc.</td></tr><tr><td><code>evidence_entity_mentions</code></td><td>Join table (where each entity appears)</td></tr><tr><td><code>evidence_events</code></td><td>Observed or extracted events</td></tr><tr><td><code>evidence_claims</code></td><td>Statements/assertions extracted from content</td></tr><tr><td><code>evidence_observations</code></td><td>Machine-grounded visual/textual facts (non-claims)</td></tr><tr><td><code>evidence_links</code></td><td>Cross-references between any two objects</td></tr><tr><td><code>evidence_conflicts</code></td><td>Detected inconsistencies (the “money” table)</td></tr><tr><td><code>evidence_timelines</code></td><td>Named timeline containers</td></tr><tr><td><code>evidence_timeline_items</code></td><td>Ordered items in timelines</td></tr><tr><td><code>evidence_reviews</code></td><td>Human review queue</td></tr></tbody></table><h2 id="processing-pipeline" tabindex="-1">Processing Pipeline <a class="header-anchor" href="#processing-pipeline" aria-label="Permalink to &quot;Processing Pipeline&quot;">​</a></h2><ol><li><strong>Ingest</strong>: Hash file, read metadata, assign evidence ID, store in <code>evidence_records</code>.</li><li><strong>Extract</strong>: <ul><li>Audio → <code>faster-whisper</code> → transcript.</li><li>Video → <code>ffmpeg</code> keyframes → <code>Qwen2.5-VL</code> observations.</li><li>Photos/Docs → OCR + <code>Qwen2.5-VL</code> description.</li></ul></li><li><strong>Structure</strong>: Populate segments, entities, events, claims, observations.</li><li><strong>Link &amp; Compare</strong>: Build links and run contradiction scanner.</li><li><strong>Timeline Assembly</strong>: Populate timelines and items.</li><li><strong>Narrate</strong>: Final cold, logical report using strict prompt rules.</li><li><strong>Review</strong>: Push uncertain/conflicting items to <code>evidence_reviews</code>.</li></ol><h2 id="narration-rules" tabindex="-1">Narration Rules <a class="header-anchor" href="#narration-rules" aria-label="Permalink to &quot;Narration Rules&quot;">​</a></h2><ul><li>No emotion words.</li><li>No speculation or intent inference.</li><li>Separate Observed / Stated / Uncertain.</li><li>Preserve timestamps and source IDs.</li><li>Mark unclear audio/visuals explicitly.</li></ul>`,17)])])}const h=n(s,[["render",o]]);export{m as __pageData,h as default};
